class Solution:
   def rotate(self, nums: list[int], n: int, k: int) -> list[int]:
      if k >= n:
         k = k % n
      k %= n
      nums[:] = nums[:n - k] + nums[n - k:][::-1]
      seen = set()
      result = []
      for num in nums:
         if num not in seen:
            seen.add(num)
            result.append(num)
      return result

