#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
class Solution {
   public:
      vector<int> rotate(vector<int>& nums, int n, int k) {
         if (k >= n) {
            k = k % n;
         }
         k %= n;
         nums = vector<int>(nums.begin(), nums.begin() + n - k) +
               vector<int>(nums.begin() + n - k, nums.end());
         sort(nums.begin(), nums.end());
         nums.resize(unique(nums.begin(), nums.end()) - nums.begin());
         return nums;
      }
};
int main() {
   ios::sync_with_stdio(false);
   cin.tie(nullptr);
   int n;
   cin >> n;
   vector<int> nums(n);
   int k;
   cin >> k;
   Solution solution;
   for (int i = 0; i < n; ++i) {
      cin >> nums[i];
   }
   for (int i = 0; i < k; ++i) {
      int temp = nums[i];
      for (int j = i; j < n - 1; ++j) {
         nums[j] = nums[j + 1];
      }
      nums[n - 1] = temp;
   }
   solution.rotate(nums, n, k);
   for (int num : nums) {
      cout << num << ' ';
   }
   cout << '\n';
   return 0;
}
